 }

 /*
- * SetKernelBrk - Adjust the kernel heap break.
- *
- * Called by malloc/free in the kernel to grow/shrink the heap.
- * Before virtual memory is enabled, simply track the break.
- * After VM is enabled, must allocate/free physical pages.
+ * Fork: copy kernel stack from parent to child.
+ * Returns parent context (child saved separately).
  */
+static SavedContext *fork_switch(SavedContext *ctxp, void *p1, void *p2) {
+    pcb_t *parent = (pcb_t *)p1;
+    pcb_t *child  = (pcb_t *)p2;
+
+    memcpy(&parent->ctx, ctxp, sizeof(SavedContext));
+    memcpy(&child->ctx, ctxp, sizeof(SavedContext));
+
+    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
+    int i;
+    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
+        int dst_pfn = child->pt[ks_base + i].pfn;
+        r1_pt[TEMP_VPN].valid = 1;
+        r1_pt[TEMP_VPN].kprot = PROT_READ | PROT_WRITE;
+        r1_pt[TEMP_VPN].uprot = PROT_NONE;
+        r1_pt[TEMP_VPN].pfn = dst_pfn;
+        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
+        memcpy((void *)TEMP_VADDR,
+               (void *)((unsigned long)(ks_base + i) << PAGESHIFT),
+               PAGESIZE);
+    }
+    r1_pt[TEMP_VPN].valid = 0;
+    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
+
+    return ctxp; /* Resume as parent */
+}
+
+/* ================================================================
+ *  Scheduling
+ * ================================================================ */
+static void schedule(ExceptionInfo *info) {
+    (void)info;
+    reap_dead();
+
+    pcb_t *next = dequeue_ready();
+    if (!next) next = idle_proc;
+    if (next == cur_proc) return;
+
+    pcb_t *old = cur_proc;
+    next->state = PROC_RUNNING;
+    next->clock_ticks = 0;
+
+    ContextSwitch(switch_func, &old->ctx, old, next);
+    /* On return, cur_proc has been set by switch_func */
+    reap_dead();
+}
+
+/* ================================================================
+ *  Process Termination
+ * ================================================================ */
+static void remove_child(pcb_t *parent, pcb_t *child) {
+    pcb_t **pp = &parent->children;
+    while (*pp && *pp != child) pp = &(*pp)->sibling;
+    if (*pp == child) *pp = child->sibling;
+    child->sibling = NULL;
+}
+
+static void terminate(pcb_t *proc, int status, ExceptionInfo *info) {
+    (void)info;
+    TracePrintf(1, "Terminate pid %d status %d\n", proc->pid, status);
+    int i;
+
+    /* Free user pages (not kernel stack) */
+    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
+    for (i = 0; i < ks_base; i++) {
+        if (proc->pt[i].valid) {
+            free_frame(proc->pt[i].pfn);
+            proc->pt[i].valid = 0;
+        }
+    }
+
+    /* Orphan all children */
+    pcb_t *ch = proc->children;
+    while (ch) {
+        pcb_t *nxt = ch->sibling;
+        ch->parent = NULL;
+        ch->sibling = NULL;
+        ch = nxt;
+    }
+    proc->children = NULL;
+
+    /* Free zombie children (they'll never be collected) */
+    pcb_t *z = proc->zombie_children;
+    while (z) {
+        pcb_t *nxt = z->zombie_next;
+        free_zombie(z);
+        z = nxt;
+    }
+    proc->zombie_children = NULL;
+
+    /* Notify parent */
+    if (proc->parent) {
+        pcb_t *par = proc->parent;
+        remove_child(par, proc);
+
+        if (par->is_waiting) {
+            /* Wake parent */
+            par->wait_child_pid = proc->pid;
+            par->wait_child_status = status;
+            par->is_waiting = 0;
+            enqueue_ready(par);
+            /* Defer cleanup of proc */
+            proc->state = PROC_DEAD;
+            proc->next = reap_list;
+            reap_list = proc;
+        } else {
+            /* Become zombie */
+            proc->state = PROC_ZOMBIE;
+            proc->exit_status = status;
+            proc->zombie_next = par->zombie_children;
+            par->zombie_children = proc;
+        }
+    } else {
+        /* Orphan - defer cleanup */
+        proc->state = PROC_DEAD;
+        proc->next = reap_list;
+        reap_list = proc;
+    }
+
+    num_procs--;
+    if (num_procs <= 0) {
+        TracePrintf(0, "All user processes exited. Halting.\n");
+        Halt();
+    }
+
+    /* Must switch away from this process */
+    pcb_t *next = dequeue_ready();
+    if (!next) next = idle_proc;
+
+    pcb_t *old = cur_proc;
+    next->state = PROC_RUNNING;
+    next->clock_ticks = 0;
+    ContextSwitch(switch_func, &old->ctx, old, next);
+    reap_dead();
+}
+
+/* ================================================================
+ *  Idle Process
+ * ================================================================ */
+static void do_idle(void) {
+    while (1) {
+        Pause();
+    }
+}
+
+/* ================================================================
+ *  Trap Handlers
+ * ================================================================ */
+static void trap_kernel(ExceptionInfo *info) {
+    int code = info->code;
+    int result;
+
+    switch (code) {
+    case YALNIX_FORK:
+        result = kern_fork(info);
+        info->regs[0] = result;
+        break;
+    case YALNIX_EXEC:
+        result = kern_exec((char *)info->regs[1], (char **)info->regs[2], info);
+        info->regs[0] = result;
+        break;
+    case YALNIX_EXIT:
+        kern_exit((int)info->regs[1], info);
+        /* Should not return for the exiting process */
+        break;
+    case YALNIX_WAIT:
+        result = kern_wait((int *)info->regs[1], info);
+        info->regs[0] = result;
+        break;
+    case YALNIX_GETPID:
+        info->regs[0] = cur_proc->pid;
+        break;
+    case YALNIX_BRK:
+        result = kern_brk((void *)info->regs[1]);
+        info->regs[0] = result;
+        break;
+    case YALNIX_DELAY:
+        result = kern_delay((int)info->regs[1], info);
+        info->regs[0] = result;
+        break;
+    case YALNIX_TTY_READ:
+        result = kern_ttyread((int)info->regs[1], (void *)info->regs[2],
+                              (int)info->regs[3], info);
+        info->regs[0] = result;
+        break;
+    case YALNIX_TTY_WRITE:
+        result = kern_ttywrite((int)info->regs[1], (void *)info->regs[2],
+                               (int)info->regs[3], info);
+        info->regs[0] = result;
+        break;
+    default:
+        TracePrintf(0, "Unknown syscall %d from pid %d\n", code, cur_proc->pid);
+        info->regs[0] = ERROR;
+        break;
+    }
+}
+
+static void trap_clock(ExceptionInfo *info) {
+    /* Decrement delay counters */
+    pcb_t **pp = &delay_q;
+    while (*pp) {
+        (*pp)->delay_remaining--;
+        if ((*pp)->delay_remaining <= 0) {
+            pcb_t *wake = *pp;
+            *pp = wake->next;
+            wake->next = NULL;
+            enqueue_ready(wake);
+        } else {
+            pp = &(*pp)->next;
+        }
+    }
+
+    /* Round-robin scheduling */
+    if (cur_proc != idle_proc) {
+        cur_proc->clock_ticks++;
+        if (cur_proc->clock_ticks >= CLOCK_QUANTUM && rq_head) {
+            enqueue_ready(cur_proc);
+            schedule(info);
+        }
+    } else {
+        /* Idle: switch to any ready process */
+        if (rq_head) {
+            schedule(info);
+        }
+    }
+}
+
+static void trap_illegal(ExceptionInfo *info) {
+    TracePrintf(0, "TRAP_ILLEGAL: pid %d, code %d, pc %p\n",
+                cur_proc->pid, info->code, info->pc);
+    if (cur_proc == idle_proc) { Halt(); }
+    terminate(cur_proc, ERROR, info);
+}
+
+static void trap_memory(ExceptionInfo *info) {
+    unsigned long addr = (unsigned long)info->addr;
+    int fault_vpn = addr >> PAGESHIFT;
+
+    /* Check if this is a stack growth request */
+    if (addr >= MEM_INVALID_SIZE && addr < (unsigned long)USER_STACK_LIMIT &&
+        fault_vpn >= cur_proc->brk_page + 1 &&  /* Red zone */
+        fault_vpn < (USER_STACK_LIMIT >> PAGESHIFT)) {
+
+        /* Grow stack down to fault_vpn */
+        int i;
+        for (i = fault_vpn; i < cur_proc->stack_base; i++) {
+            if (cur_proc->pt[i].valid) continue;
+            int pfn = alloc_frame();
+            if (pfn < 0) goto kill;
+            cur_proc->pt[i].valid = 1;
+            cur_proc->pt[i].kprot = PROT_READ | PROT_WRITE;
+            cur_proc->pt[i].uprot = PROT_READ | PROT_WRITE;
+            cur_proc->pt[i].pfn = pfn;
+        }
+        cur_proc->stack_base = fault_vpn;
+        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
+        return;
+    }
+
+kill:
+    TracePrintf(0, "TRAP_MEMORY: pid %d, addr %p, code %d\n",
+                cur_proc->pid, info->addr, info->code);
+    if (cur_proc == idle_proc) { Halt(); }
+    terminate(cur_proc, ERROR, info);
+}
+
+static void trap_math(ExceptionInfo *info) {
+    TracePrintf(0, "TRAP_MATH: pid %d, code %d\n", cur_proc->pid, info->code);
+    if (cur_proc == idle_proc) { Halt(); }
+    terminate(cur_proc, ERROR, info);
+}
+
+static void trap_tty_recv(ExceptionInfo *info) {
+    int tty = info->code;
+    if (tty < 0 || tty >= NUM_TERMINALS) return;
+
+    /* Read from hardware into a new buffer */
+    tty_line_t *line = (tty_line_t *)malloc(sizeof(tty_line_t));
+    if (!line) return;
+    line->len = TtyReceive(tty, line->data, TERMINAL_MAX_LINE);
+    line->next = NULL;
+
+    /* Append to input queue */
+    if (!tty_in_tail[tty]) {
+        tty_in_head[tty] = tty_in_tail[tty] = line;
+    } else {
+        tty_in_tail[tty]->next = line;
+        tty_in_tail[tty] = line;
+    }
+
+    /* Wake blocked reader if any */
+    if (tty_rd_wait[tty]) {
+        pcb_t *reader = tty_rd_wait[tty];
+        tty_rd_wait[tty] = reader->next;
+        reader->next = NULL;
+        enqueue_ready(reader);
+    }
+}
+
+static void trap_tty_xmit(ExceptionInfo *info) {
+    int tty = info->code;
+    if (tty < 0 || tty >= NUM_TERMINALS) return;
+
+    /* Current transmit is done; unblock the writer */
+    pcb_t *writer = tty_wr_active[tty];
+    tty_wr_active[tty] = NULL;
+    if (writer) {
+        if (writer->wr_buf) { free(writer->wr_buf); writer->wr_buf = NULL; }
+        enqueue_ready(writer);
+    }
+
+    /* Start next pending write if any */
+    if (tty_wr_head[tty]) {
+        pcb_t *nw = tty_wr_head[tty];
+        tty_wr_head[tty] = nw->next;
+        if (!tty_wr_head[tty]) tty_wr_tail[tty] = NULL;
+        nw->next = NULL;
+        tty_wr_active[tty] = nw;
+        TtyTransmit(tty, nw->wr_buf, nw->wr_len);
+    }
+}
