+/* ================================================================
+ *  LoadProgram (adapted from load.template)
+ * ================================================================ */
+static int
+load_program(char *name, char **args, ExceptionInfo *info, pcb_t *proc)
+{
+    int fd;
+    int status;
+    struct loadinfo li;
+    char *cp;
+    char *cp2;
+    char **cpp;
+    char *argbuf;
+    int i;
+    unsigned long argcount;
+    int size;
+    int text_npg;
+    int data_bss_npg;
+    int stack_npg;
+
+    TracePrintf(1, "LoadProgram '%s', args %p\n", name, args);
+
+    if ((fd = open(name, O_RDONLY)) < 0) {
+        TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
+        return (-1);
+    }
+
+    status = LoadInfo(fd, &li);
+    TracePrintf(1, "LoadProgram: LoadInfo status %d\n", status);
+    switch (status) {
+    case LI_SUCCESS:
+        break;
+    case LI_FORMAT_ERROR:
+        TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
+        close(fd);
+        return (-1);
+    case LI_OTHER_ERROR:
+        TracePrintf(0, "LoadProgram: '%s' other error\n", name);
+        close(fd);
+        return (-1);
+    default:
+        TracePrintf(0, "LoadProgram: '%s' unknown error\n", name);
+        close(fd);
+        return (-1);
+    }
+    TracePrintf(1, "text_size 0x%lx, data_size 0x%lx, bss_size 0x%lx\n",
+                li.text_size, li.data_size, li.bss_size);
+    TracePrintf(1, "entry 0x%lx\n", li.entry);
+
+    /*
+     *  Figure out how many bytes for arguments on new stack.
+     */
+    size = 0;
+    for (i = 0; args[i] != NULL; i++) {
+        size += strlen(args[i]) + 1;
+    }
+    argcount = i;
+    TracePrintf(1, "LoadProgram: size %d, argcount %d\n", size, (int)argcount);
+
+    /*
+     *  Save arguments in Region 1 buffer.
+     */
+    cp = argbuf = (char *)malloc(size);
+    if (!argbuf) { close(fd); return (-1); }
+    for (i = 0; args[i] != NULL; i++) {
+        strcpy(cp, args[i]);
+        cp += strlen(cp) + 1;
+    }
+
+    /*
+     *  Compute stack layout.
+     */
+    cp = ((char *)USER_STACK_LIMIT) - size;
+    cpp = (char **)((unsigned long)cp & (~0xFUL));     /* align cpp */
+    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));
+
+    text_npg = li.text_size >> PAGESHIFT;
+    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
+    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;
+
+    TracePrintf(1, "LoadProgram: text_npg %d, data_bss_npg %d, stack_npg %d\n",
+                text_npg, data_bss_npg, stack_npg);
+
+    /*
+     *  Check virtual memory size.
+     */
+    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
+        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
+        TracePrintf(0, "LoadProgram: '%s' too large for VIRTUAL memory\n", name);
+        free(argbuf);
+        close(fd);
+        return (-1);
+    }
+
+    /*
+     *  Check physical memory (accounting for pages that will be freed).
+     */
+    {
+        int pages_needed = text_npg + data_bss_npg + stack_npg;
+        int pages_to_free = 0;
+        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
+        for (i = 0; i < ks_base_vpn; i++) {
+            if (proc->pt[i].valid) pages_to_free++;
+        }
+        if (pages_needed - pages_to_free > num_free) {
+            TracePrintf(0, "LoadProgram: '%s' too large for PHYSICAL memory\n", name);
+            free(argbuf);
+            close(fd);
+            return (-1);
+        }
+    }
+
+    /* Initialize sp */
+    info->sp = (void *)cpp;
+
+    /*
+     *  Free old Region 0 pages (except kernel stack).
+     */
+    {
+        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
+        for (i = 0; i < ks_base_vpn; i++) {
+            if (proc->pt[i].valid) {
+                free_frame(proc->pt[i].pfn);
+                proc->pt[i].valid = 0;
+            }
+        }
+    }
+
+    /*
+     *  Set up text, data+bss, stack pages.
+     */
+    {
+        int vpn = MEM_INVALID_PAGES;
+
+        /* Text pages */
+        for (i = 0; i < text_npg; i++) {
+            int pfn = alloc_frame();
+            proc->pt[vpn].valid = 1;
+            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
+            proc->pt[vpn].uprot = PROT_READ | PROT_EXEC;
+            proc->pt[vpn].pfn = pfn;
+            vpn++;
+        }
+
+        /* Data + BSS pages */
+        for (i = 0; i < data_bss_npg; i++) {
+            int pfn = alloc_frame();
+            proc->pt[vpn].valid = 1;
+            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
+            proc->pt[vpn].uprot = PROT_READ | PROT_WRITE;
+            proc->pt[vpn].pfn = pfn;
+            vpn++;
+        }
+
+        /* Update brk for this process */
+        proc->brk_page = vpn;
+
+        /* Stack pages (at top of Region 0 user area) */
+        int stack_top_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
+        for (i = 0; i < stack_npg; i++) {
+            int sv = stack_top_vpn - stack_npg + 1 + i;
+            int pfn = alloc_frame();
+            proc->pt[sv].valid = 1;
+            proc->pt[sv].kprot = PROT_READ | PROT_WRITE;
+            proc->pt[sv].uprot = PROT_READ | PROT_WRITE;
+            proc->pt[sv].pfn = pfn;
+        }
+        proc->stack_base = stack_top_vpn - stack_npg + 1;
+    }
+
+    /* Flush TLB for Region 0 */
+    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
+
+    /*
+     *  Read text and data from file.
+     */
+    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
+        != (ssize_t)(li.text_size + li.data_size)) {
+        TracePrintf(0, "LoadProgram: couldn't read for '%s'\n", name);
+        free(argbuf);
+        close(fd);
+        return (-2);
+    }
+
+    close(fd);
+
+    /*
+     *  Set text pages to read/exec (was read/write for loading).
+     */
+    {
+        int vpn = MEM_INVALID_PAGES;
+        for (i = 0; i < text_npg; i++) {
+            proc->pt[vpn + i].kprot = PROT_READ | PROT_EXEC;
+        }
+    }
+    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
+
+    /*
+     *  Zero out BSS.
+     */
+    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
+           '\0', li.bss_size);
+
+    /*
+     *  Set entry point.
+     */
+    info->pc = (void *)li.entry;
+
+    /*
+     *  Build argument list on the new stack.
+     */
+    *cpp++ = (char *)argcount;
+    cp2 = argbuf;
+    for (i = 0; (unsigned long)i < argcount; i++) {
+        *cpp++ = cp;
+        strcpy(cp, cp2);
+        cp += strlen(cp) + 1;
+        cp2 += strlen(cp2) + 1;
+    }
+    free(argbuf);
+    *cpp++ = NULL;   /* argv terminator */
+    *cpp++ = NULL;   /* envp terminator */
+    *cpp++ = 0;      /* aux vector terminator */
+
+    /*
+     *  Initialize registers.
+     */
+    for (i = 0; i < NUM_REGS; i++) {
+        info->regs[i] = 0;
+    }
+    info->psr = 0;
+
+    return (0);
+}
